#include <stdio.h>
#include <stdlib.h>

int main() {
    // 1. Borrow memory
    int *ptr = malloc(100 * sizeof(int));

    // 2. Use it (pretend we did cool stuff here)
    ptr[0] = 99;

    // 3. RETURN it!
    free(ptr);

    // After free(), accessing ptr is strictly forbidden!
    // ptr[0] = 50; // CRASH!
    return 0;
}
